def get_sum(a: int, b: int) -> int:
    MASK = 0xFFFFFFFF
    MAX_INT = 0x7FFFFFFF

    def add(x, y):
        if y == 0:
            return x
        carry = ((x & y) << 1) & MASK
        no_carry = (x ^ y) & MASK
        return add(no_carry, carry)

    result = add(a & MASK, b & MASK)
    if result > MAX_INT:
        result = ~(result ^ MASK)
    return result

function getSum(a, b) {
    while (b !== 0) {
        const carry = (a & b) << 1;
        a = a ^ b;
        b = carry;
    }
    return a;
}
